options(stringsAsFactors = FALSE, scipen = 999)
root <- normalizePath(getwd(), winslash='/', mustWork=TRUE)
p <- function(...) file.path(root,...)
for (d in c('docs','outputs/reports','outputs/tables/csv','paper','scripts','config')) if (!dir.exists(p(d))) dir.create(p(d), recursive=TRUE)
library(data.table)
wc <- function(lines) length(gregexpr('[A-Za-z0-9]+', paste(lines, collapse=' '), perl=TRUE)[[1]])
esc <- function(x){x<-gsub('&','&amp;',x,fixed=TRUE);x<-gsub('<','&lt;',x,fixed=TRUE);gsub('>','&gt;',x,fixed=TRUE)}
q <- readLines(p('paper/main.qmd'), warn=FALSE, encoding='UTF-8')
body <- character(); in_yaml <- FALSE
for (ln in q) {
  if (ln == '---') { in_yaml <- !in_yaml; next }
  if (in_yaml || grepl('^(title|subtitle|author|date|format|bibliography):', ln)) next
  if (grepl('^# ', ln)) body <- c(body, paste0('<h1>', esc(sub('^# ', '', ln)), '</h1>'))
  else if (grepl('^## ', ln)) body <- c(body, paste0('<h2>', esc(sub('^## ', '', ln)), '</h2>'))
  else if (grepl('^!\\[', ln)) { alt <- sub('^!\\[([^]]*)\\].*$', '\\1', ln); src <- sub('^!\\[[^]]*\\]\\(([^)]+)\\).*$', '\\1', ln); body <- c(body, paste0('<figure><img src="', esc(src), '" alt="', esc(alt), '"><figcaption>', esc(alt), '</figcaption></figure>')) }
  else if (nzchar(trimws(ln))) body <- c(body, paste0('<p>', esc(ln), '</p>'))
}
html <- c('<!doctype html><html><head><meta charset="utf-8"><title>Economic Complexity and Structural Transformation in Latin America</title><style>body{font-family:Arial,sans-serif;max-width:980px;margin:36px auto;line-height:1.58;color:#202020}h1,h2{color:#17233c}img{max-width:100%;border:1px solid #ddd}figure{margin:24px 0}figcaption{color:#555;font-size:.92em}code{background:#f4f4f4;padding:2px 4px}</style></head><body>', body, '</body></html>')
writeLines(html, p('paper/main.html'), useBytes=TRUE)
text_only <- q[!grepl('^---$|^(title|subtitle|author|date|format|bibliography):|^!\\[', q)]
tex_escape <- function(x){x<-gsub('\\\\','\\\\textbackslash{}',x); x<-gsub('([#$%&_{}])','\\\\\\1',x,perl=TRUE); x}
tex_lines <- tex_escape(text_only)
tex_lines <- gsub('^# (.*)$','\\\\section{\\1}',tex_lines)
tex_lines <- gsub('^## (.*)$','\\\\subsection{\\1}',tex_lines)
tex <- c('\\documentclass[11pt]{article}','\\usepackage[margin=1in]{geometry}','\\usepackage{hyperref}','\\title{Economic Complexity and Structural Transformation in Latin America}','\\author{Monica Cueto Tapia}','\\date{2026-07-11}','\\begin{document}','\\maketitle',tex_lines,'\\end{document}')
writeLines(tex, p('paper/main.tex'), useBytes=TRUE)
words <- wc(text_only)
figs <- if (file.exists(p('outputs/tables/csv/figure_audit.csv'))) fread(p('outputs/tables/csv/figure_audit.csv')) else data.table(status=character())
writeLines(c('# Paper Completeness Audit','',paste0('- `paper/main.qmd`: present; word count approximately ', words, '.'),paste0('- `paper/main.html`: ', file.exists(p('paper/main.html')), '.'),paste0('- `paper/main.tex`: ', file.exists(p('paper/main.tex')), '.'),paste0('- `paper/main.pdf`: ', file.exists(p('paper/main.pdf')), '.'),paste0('- Passing figures available: ', figs[status=='PASS', .N], '.'),'',if (words >= 7000) 'Status: PASS for long-form working-paper length.' else 'Status: WARNING. The manuscript is a complete working draft but below the 7,000-word journal-article target.','', 'Use `scripts/render_paper.R` to attempt local HTML/PDF rendering with detected tools.'), p('docs/PAPER_COMPLETENESS_AUDIT.md'), useBytes=TRUE)
render_r <- c("options(stringsAsFactors=FALSE)","root <- normalizePath(getwd(), winslash='/', mustWork=TRUE)","report <- file.path(root, 'outputs/reports/PAPER_RENDER_REPORT.md')","tools <- Sys.which(c('quarto','pandoc','pdflatex','xelatex','lualatex'))","lines <- c('# Paper Render Report','',paste0('- quarto: ', ifelse(nzchar(tools[['quarto']]), tools[['quarto']], 'not found')),paste0('- pandoc: ', ifelse(nzchar(tools[['pandoc']]), tools[['pandoc']], 'not found')),paste0('- pdflatex: ', ifelse(nzchar(tools[['pdflatex']]), tools[['pdflatex']], 'not found')))","if (nzchar(tools[['quarto']])) lines <- c(lines, '', '## Quarto', paste(system2(tools[['quarto']], c('render', file.path(root,'paper/main.qmd'), '--to', 'html'), stdout=TRUE, stderr=TRUE), collapse='\\n')) else lines <- c(lines, '', '## Quarto', 'Quarto was not found on PATH; using prebuilt paper/main.html.')","if (nzchar(tools[['pdflatex']]) && file.exists(file.path(root,'paper/main.tex'))) { old <- getwd(); setwd(file.path(root,'paper')); out1 <- system2(tools[['pdflatex']], c('-interaction=nonstopmode','-halt-on-error','main.tex'), stdout=TRUE, stderr=TRUE); out2 <- system2(tools[['pdflatex']], c('-interaction=nonstopmode','-halt-on-error','main.tex'), stdout=TRUE, stderr=TRUE); setwd(old); lines <- c(lines, '', '## LaTeX PDF', paste(tail(c(out1,out2), 80), collapse='\\n')) } else lines <- c(lines, '', '## LaTeX PDF', 'No LaTeX engine or paper/main.tex available; PDF not rendered.')","lines <- c(lines, '', paste0('- HTML exists: ', file.exists(file.path(root,'paper/main.html'))), paste0('- PDF exists: ', file.exists(file.path(root,'paper/main.pdf'))))","writeLines(lines, report, useBytes=TRUE)","cat(paste(lines, collapse='\\n'))")
writeLines(render_r, p('scripts/render_paper.R'), useBytes=TRUE)
writeLines(c("$ErrorActionPreference = 'Stop'","$root = Split-Path -Parent $PSScriptRoot","Set-Location $root","$rscript = Get-Command Rscript -ErrorAction SilentlyContinue","if (-not $rscript) { throw 'Rscript was not found on PATH. Run scripts/render_paper.R with your local Rscript executable.' }","& $rscript.Source 'scripts/render_paper.R'"), p('scripts/render_paper.ps1'), useBytes=TRUE)
pkgs <- c('shiny','data.table','ggplot2','plotly','DT')
pkg_status <- data.table(package=pkgs, available=vapply(pkgs, requireNamespace, logical(1), quietly=TRUE))
fwrite(pkg_status, p('outputs/tables/csv/dashboard_package_check.csv'))
dash_parse <- tryCatch({parse(p('dashboard/app.R')); TRUE}, error=function(e) FALSE)
writeLines(c('# Dashboard Test Report','',paste0('- `dashboard/app.R` parses: ', dash_parse, '.'),paste0('- Required packages available: ', sum(pkg_status$available), '/', nrow(pkg_status), '.'),paste0('- Country-year indicators present: ', file.exists(p('outputs/tables/csv/country_year_indicators.csv')), '.'),paste0('- Revised opportunities present: ', file.exists(p('outputs/tables/csv/bolivia_opportunities_revised.csv')), '.'),'','Run with `Rscript scripts/run_dashboard.R` or `shiny::runApp("dashboard")` from the repository root.'), p('outputs/reports/DASHBOARD_TEST_REPORT.md'), useBytes=TRUE)
cy <- fread(p('outputs/tables/csv/country_year_indicators.csv')); bol <- cy[country_code=='BOL' & year==max(cy[country_code=='BOL' & export_value>0, year])]
opp <- fread(p('outputs/tables/csv/bolivia_opportunities_revised.csv')); rel <- opp[, .N, by=relative_category][order(-N)]
ps <- fread(p('outputs/tables/csv/product_space_network_diagnostics.csv'))
readme <- c('# Economic Complexity and Structural Transformation in Latin America','','**Productive capabilities, divergent development paths, and diversification opportunities for Bolivia**','','Monica Cueto Tapia  ','Applied Economist | Development Analytics | Economic Complexity | Public Policy | Data Science','','![ECI trends](outputs/figures/png/01_eci_latin_america_trends.png)','','## Research Question','','To what extent do economic complexity, export diversification, and proximity to more sophisticated products explain divergent structural transformation and growth trajectories in Latin America, and what feasible diversification opportunities exist for Bolivia?','','## What This Repository Contains','','- A local-data R pipeline for HS92 country-product-year trade analysis.','- RCA, MCP, diversity, ubiquity, HHI, entropy, ECI, projected PCI, Product Space proximity, density, and opportunity scoring.','- A Bolivia opportunity workbook with strict absolute categories and revised relative feasibility categories.','- Validation reports for RCA, ECI/PCI, Product Space, Bolivia indicators, figures, models, dashboard, and final repository readiness.','- A Shiny dashboard and a paper-style manuscript generated from local outputs.','','## Key Results','',paste0('- Bolivia ', bol$year, ': ECI ', round(bol$eci,3), ', diversity ', bol$diversity, ', HHI ', round(bol$hhi,3), ', primary export share ', round(100*bol$primary_share,1), ' percent.'),paste0('- Revised eligible Bolivia opportunity universe: ', opp[eligible==TRUE,.N], ' products.'),paste0('- Relative categories: ', paste(rel[, paste(relative_category, N, sep=' = ')], collapse='; '), '.'),paste0('- Product Space diagnostics: ', ps[metric=='analytical_positive_edges', value], ' analytical positive edges; ', ps[metric=='visual_edges', value], ' visual edges.'),'','## Priority Outputs','','- `paper/main.html`','- `paper/main.qmd`','- `outputs/tables/xlsx/bolivia_opportunities_revised.xlsx`','- `outputs/tables/csv/bolivia_top40_economic_review.csv`','- `outputs/figures/png/06_bolivia_product_space.png`','- `outputs/figures/png/07_bolivia_density_pci.png`','- `outputs/figures/png/08_bolivia_opportunity_matrix.png`','- `dashboard/app.R`','- `docs/REPRODUCIBILITY.md`','- `outputs/reports/FINAL_REPOSITORY_CHECK.md`','','## Reproduce','','Create `config/paths.local.yml` from `config/paths.example.yml` and point it to local source data. The local paths file is ignored by Git. Then run:','','```powershell','Rscript R/99_run_all.R','Rscript scripts/phase2_stage2_validation.R','Rscript scripts/phase2_stage3_models_figures.R','Rscript scripts/phase2_stage4_dashboard_paper_docs.R','Rscript scripts/phase2_stage5_samples_tests_cleanup.R','```','','Run the dashboard with `Rscript scripts/run_dashboard.R`.','','## Data Policy','','Raw source files, large processed caches, local absolute paths, and model RDS files are excluded from Git. Public outputs use relative paths and sample files. No web calls, APIs, or new downloads are required for the Phase 2 validation and packaging scripts.','','## Limitations','','Opportunity scores are screening tools, not investment recommendations. The econometric models are observational fixed-effects associations and should not be interpreted causally. Sector studies are required before policy prioritization.','','## License','','MIT License.')
writeLines(readme, p('README.md'), useBytes=TRUE)
writeLines(c('# Reproducibility','','## Levels','','- Level 1, public inspection: read scripts, docs, samples, paper, figures, and CSV summaries without raw data.','- Level 2, processed-cache rerun: rerun validation, figure, dashboard, paper, sample, and final-check scripts from processed outputs.','- Level 3, full rebuild: provide local source paths in `config/paths.local.yml` and run `R/99_run_all.R`.','','## Local Paths','','Personal absolute source paths must appear only in `config/paths.local.yml`. This file is ignored by Git. Public files should use placeholders or relative paths.','','## Randomness','','The Phase 2 figure scripts use seed `20260711` for network layout reproducibility.','','## Expected Ignored Files','','- `data/raw/`','- `data/interim/*.rds` and `data/interim/*.parquet`','- `data/processed/*.rds` and `data/processed/*.parquet`','- `outputs/models/*.rds`','- `paper/*.pdf`','- `config/paths.local.yml`','','## Main Commands','','```powershell','Rscript scripts/validate_project.R','Rscript scripts/phase2_stage2_validation.R','Rscript scripts/phase2_stage3_models_figures.R','Rscript scripts/phase2_stage4_dashboard_paper_docs.R','Rscript scripts/phase2_stage5_samples_tests_cleanup.R','```'), p('docs/REPRODUCIBILITY.md'), useBytes=TRUE)
writeLines(c('# GitHub Repository Description','','Economic complexity and structural transformation in Latin America, with a reproducible local-data R pipeline and a Bolivia diversification opportunity screen.','','Suggested topics: `economic-complexity`, `structural-transformation`, `latin-america`, `bolivia`, `rca`, `product-space`, `r`, `development-economics`, `trade-data`, `reproducible-research`.'), p('docs/GITHUB_REPOSITORY_DESCRIPTION.md'), useBytes=TRUE)
writeLines(c('# GitHub Release Checklist','','- [ ] Confirm `config/paths.local.yml` is ignored and not staged.','- [ ] Confirm no raw source data or large processed parquet files are staged.','- [ ] Run `Rscript scripts/phase2_stage5_samples_tests_cleanup.R`.','- [ ] Review `outputs/reports/FINAL_REPOSITORY_CHECK.md`.','- [ ] Review paper HTML and dashboard locally.','- [ ] Decide whether to attach ignored PDF artifacts to a release outside Git.','- [ ] Create the first commit only after the final check has no FAIL items.'), p('docs/GITHUB_RELEASE_CHECKLIST.md'), useBytes=TRUE)
